# Create an Azure Blueprint definition via CLI
# NOTE: Azure Blueprints is deprecated as of July 11, 2026.
# Use Deployment Stacks for new environments.

# Blueprint definitions are stored at a management group or subscription scope.
# Management group scope is preferred — one definition serves all child subscriptions.

MG_ID='alz-landing-zones'    # Parent management group for the blueprint definition
BP_NAME='landing-zone-baseline'

# 1. Create the blueprint definition (draft state)
az blueprint create \
  --name $BP_NAME \
  --management-group $MG_ID \
  --display-name 'Landing Zone Baseline' \
  --description 'Deploys baseline resources and policies for a landing zone subscription' \
  --target-scope subscription \
  --parameters '{
    "subscriptionLocation": {
      "type": "string",
      "defaultValue": "eastus",
      "metadata": {"displayName": "Primary region for resources"}
    },
    "logAnalyticsWorkspaceId": {
      "type": "string",
      "metadata": {"displayName": "Log Analytics workspace resource ID"}
    },
    "appTeamGroupObjectId": {
      "type": "string",
      "metadata": {"displayName": "App team AAD group object ID for Contributor access"}
    }
  }' \
  --resource-groups '{
    "rg-workloads": {
      "location": "[parameters(\"subscriptionLocation\")]"
    },
    "rg-monitoring": {
      "location": "[parameters(\"subscriptionLocation\")]"
    }
  }'

# 2. Verify the draft definition was created
az blueprint show \
  --name $BP_NAME \
  --management-group $MG_ID \
  --query '{Name:name, Status:status, TargetScope:targetScope}' -o table
